import { useCallback, useEffect, useState } from "react";
import "./App.css";
import AnalyticsDashboard from "./components/AnalyticsDashboard";
import AuthPage from "./components/AuthPage";
import LiveAttackFeed from "./components/LiveAttackFeed";
import Scanner from "./components/Scanner";
import { getAnalytics, getAttackFeed } from "./services/api";

function Dashboard({ session, onLogout }) {
  const [darkMode, setDarkMode] = useState(false);
  const [analytics, setAnalytics] = useState({ total: 0, phishingPercent: 0, distribution: [], daily: [] });
  const [feed, setFeed] = useState([]);
  const [analyticsLoading, setAnalyticsLoading] = useState(false);
  const isAdmin = session.user.role === "admin";

  const refreshAdminData = useCallback(async () => {
    if (!isAdmin) return;
    setAnalyticsLoading(true);
    try {
      const [nextAnalytics, nextFeed] = await Promise.all([getAnalytics(), getAttackFeed()]);
      setAnalytics(nextAnalytics);
      setFeed(nextFeed);
    } catch (error) {
      if (error.response?.status === 401) onLogout();
    } finally {
      setAnalyticsLoading(false);
    }
  }, [isAdmin, onLogout]);

  useEffect(() => {
    refreshAdminData();
    const interval = setInterval(refreshAdminData, 5000);
    return () => clearInterval(interval);
  }, [refreshAdminData]);

  return (
    <main className={darkMode ? "app-frame dark" : "app-frame"}>
      <aside className="sidebar glass">
        <div className="brand-lockup">
          <div className="brand-mark">AI</div>
          <div><strong>PhishGuard</strong><span>Security workspace</span></div>
        </div>
        <nav className="side-nav" aria-label="Workspace navigation">
          <a className="active" href="#scanner">Scanner</a>
          {isAdmin && <a href="#analytics">Analytics</a>}
          {isAdmin && <a href="#feed">Live Feed</a>}
        </nav>
        <div className="sidebar-card">
          <span>Signed in as</span>
          <strong className="small-strong">{session.user.email}</strong>
          <span className="role-chip">{session.user.role}</span>
          <button className="secondary-button full" onClick={() => setDarkMode((value) => !value)} type="button">
            {darkMode ? "Light mode" : "Dark mode"}
          </button>
          <button className="secondary-button full" onClick={onLogout} type="button">Logout</button>
        </div>
      </aside>

      <section className="main-workspace">
        <header className="workspace-topbar">
          <div><p className="eyebrow">Threat intelligence console</p><h1>AI Phishing Detector</h1></div>
          <div className="live-verdict"><span>Session</span><strong>{session.user.role}</strong></div>
        </header>

        <Scanner onScanComplete={refreshAdminData} />

        {isAdmin ? (
          <>
            <section id="analytics"><AnalyticsDashboard analytics={analytics} loading={analyticsLoading} /></section>
            <section id="feed" className="feed-section"><LiveAttackFeed items={feed} /></section>
          </>
        ) : (
          <article className="glass permission-card">
            <p className="eyebrow">User role</p>
            <h3>Scan-only access</h3>
            <p>Admin analytics and logs are protected by role-based JWT authorization.</p>
          </article>
        )}
      </section>
    </main>
  );
}

function App() {
  const [session, setSession] = useState(() => {
    const stored = localStorage.getItem("phishguardSession");
    return stored ? JSON.parse(stored) : null;
  });

  const handleAuth = (nextSession) => {
    localStorage.setItem("phishguardSession", JSON.stringify(nextSession));
    setSession(nextSession);
  };

  const handleLogout = () => {
    localStorage.removeItem("phishguardSession");
    setSession(null);
  };

  if (!session) return <AuthPage onAuth={handleAuth} />;
  return <Dashboard onLogout={handleLogout} session={session} />;
}

export default App;
