import { useState } from "react";
import { login, register } from "../services/api";

export default function AuthPage({ onAuth }) {
  const [mode, setMode] = useState("login");
  const [form, setForm] = useState({
    name: "Security User",
    email: "user@example.com",
    password: "user123",
  });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const update = (key, value) => setForm((current) => ({ ...current, [key]: value }));

  const submit = async (event) => {
    event.preventDefault();
    setLoading(true);
    setError("");
    try {
      const session =
        mode === "login"
          ? await login({ email: form.email, password: form.password })
          : await register(form);
      onAuth(session);
    } catch (err) {
      setError(err.response?.data?.error || "Authentication failed.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="login-screen">
      <section className="login-brand-panel glass">
        <div className="brand-lockup large">
          <div className="brand-mark">AI</div>
          <div>
            <strong>PhishGuard</strong>
            <span>AI threat detection workspace</span>
          </div>
        </div>
        <div className="login-copy">
          <p className="eyebrow">Secure analyst portal</p>
          <h1>Detect risky emails, links, and SMS before they spread.</h1>
          <p>JWT-protected scanning, explainable AI, live attack feed, and admin analytics.</p>
        </div>
        <div className="login-stats">
          <span><strong>333</strong>training samples</span>
          <span><strong>3</strong>scan channels</span>
          <span><strong>JWT</strong>auth enabled</span>
        </div>
      </section>

      <section className="login-card glass" aria-label="Authentication form">
        <div className="auth-tabs">
          <button className={mode === "login" ? "active" : ""} onClick={() => setMode("login")} type="button">Login</button>
          <button className={mode === "register" ? "active" : ""} onClick={() => setMode("register")} type="button">Register</button>
        </div>
        <p className="eyebrow">Welcome back</p>
        <h2>{mode === "login" ? "Sign in to dashboard" : "Create analyst account"}</h2>
        <form onSubmit={submit}>
          {mode === "register" && (
            <label>Name<input value={form.name} onChange={(event) => update("name", event.target.value)} /></label>
          )}
          <label>Email address<input type="email" value={form.email} onChange={(event) => update("email", event.target.value)} /></label>
          <label>Password<input type="password" value={form.password} onChange={(event) => update("password", event.target.value)} /></label>
          {error && <p className="error-text">{error}</p>}
          <button className="primary-button full" disabled={loading} type="submit">
            {loading ? "Please wait" : mode === "login" ? "Login" : "Create account"}
          </button>
          <p className="hint">Demo admin: admin@phishguard.ai / admin123</p>
          <p className="hint">Demo user: user@phishguard.ai / user123</p>
          {mode === "register" && <p className="hint">New registrations are always user accounts.</p>}
        </form>
      </section>
    </main>
  );
}
